  {
    type: 'function',
    function: {
      name: 'update_task',
      description: 'Update an existing task status or details.',
      parameters: {
        type: 'object',
        properties: {
          task_id:  { type: 'string', description: 'UUID of the task' },
          status:   { type: 'string', enum: ['pending','in_progress','done','cancelled'] },
          title:    { type: 'string' },
          deadline: { type: 'string' },
          priority: { type: 'string', enum: ['low','medium','high'] }
        },
        required: ['task_id']
      }
    }
  },
  {
    type: 'function',
    function: {
      name: 'check_in',
      description: 'Record attendance check-in for the current user.',
      parameters: { type: 'object', properties: {} }
    }
  },
  {
    type: 'function',
    function: {
      name: 'check_out',
      description: 'Record attendance check-out for the current user.',
      parameters: { type: 'object', properties: {} }
    }
  },
  {
    type: 'function',
    function: {
      name: 'check_leave_balance',
      description: 'Get remaining leave balance for the current user.',
      parameters: { type: 'object', properties: {} }
