// ── Tool executor ───────────────────────────────────────────────────────────
async function runTool(name, args) {
  const today = new Date().toLocaleDateString('en-CA', { timeZone: 'Asia/Kolkata' });

  if (name === 'list_tasks') {
    // Admin/manager: all org tasks; employee: only own tasks
    const userFilter = isAdmin ? '' : '&assignee_id=eq.' + userId;
    return helpers.httpRequest({
      method: 'GET',
      url: sbUrl + '/rest/v1/tasks?status=not.in.(done,cancelled)&deleted_at=is.null&organization_id=eq.' + orgId +
           userFilter +
           '&select=id,title,deadline,priority,status,assignee:users!tasks_assignee_id_fkey(full_name)' +
           '&order=deadline.asc.nullslast&limit=30',
      headers: sbHeaders
    });
  }

  if (name === 'create_task') {
    return helpers.httpRequest({
      method: 'POST',
      url: sbUrl + '/rest/v1/rpc/create_task_from_bot',
      headers: { ...sbHeaders, 'Content-Type': 'application/json' },
      body: JSON.stringify({
        p_title:         args.title,
        p_deadline:      args.deadline ?? null,
        p_priority:      args.priority ?? 'medium',
        p_org_id:        orgId,
        p_assignee_name: args.assignee_name ?? '',
        p_creator_id:    userId
      })
    });
  }

  if (name === 'update_task') {
    return helpers.httpRequest({
      method: 'POST',
      url: sbUrl + '/rest/v1/rpc/update_task_from_bot',
      headers: { ...sbHeaders, 'Content-Type': 'application/json' },
      body: JSON.stringify({
        p_task_id:  args.task_id,
        p_status:   args.status   ?? null,
        p_title:    args.title    ?? null,
        p_deadline: args.deadline ?? null,
        p_priority: args.priority ?? null
      })
    });
  }

  if (name === 'check_in') {
    return helpers.httpRequest({
      method: 'POST',
      url: sbUrl + '/rest/v1/rpc/attendance_check_in',
      headers: { ...sbHeaders, 'Content-Type': 'application/json' },
      body: JSON.stringify({ p_user_id: userId, p_org_id: orgId })
    });
  }

  if (name === 'check_out') {
    return helpers.httpRequest({
      method: 'POST',
      url: sbUrl + '/rest/v1/rpc/attendance_check_out',
      headers: { ...sbHeaders, 'Content-Type': 'application/json' },
      body: JSON.stringify({ p_user_id: userId, p_org_id: orgId })
    });
  }

  if (name === 'check_leave_balance') {
    return helpers.httpRequest({
      method: 'GET',
      url: sbUrl + '/rest/v1/leave_balances?employee_id=eq.' + userId +
           '&organization_id=eq.' + orgId + '&select=balance_days,leave_type:leave_types(name)',
      headers: sbHeaders
    });
  }

  if (name === 'apply_leave') {
    return helpers.httpRequest({
      method: 'POST',
      url: sbUrl + '/rest/v1/rpc/apply_leave_from_bot',
      headers: { ...sbHeaders, 'Content-Type': 'application/json' },
      body: JSON.stringify({
        p_employee_id:   userId,
        p_org_id:        orgId,
        p_leave_type_id: args.leave_type_id,
        p_start_date:    args.start_date,
        p_end_date:      args.end_date,
        p_reason:        args.reason ?? ''
      })
    });
  }

  if (name === 'list_leaves') {
    return helpers.httpRequest({
      method: 'GET',
      url: sbUrl + '/rest/v1/leave_requests?employee_id=eq.' + userId +
           '&organization_id=eq.' + orgId +
           '&select=start_date,end_date,duration_days,status,reason,leave_type:leave_types(name)' +
           '&order=created_at.desc&limit=10',
      headers: sbHeaders
    });
  }

  if (name === 'daily_briefing') {
    return helpers.httpRequest({
      method: 'GET',
      url: sbUrl + '/rest/v1/rpc/daily_briefing_for_bot?p_user_id=' + userId + '&p_org_id=' + orgId,
      headers: sbHeaders
    });
  }

  if (name === 'my_attendance') {
    const now = new Date();
    const monthStart = new Date(now.getFullYear(), now.getMonth(), 1).toISOString().split('T')[0];
    return helpers.httpRequest({
      method: 'GET',
      url: sbUrl + '/rest/v1/attendance?user_id=eq.' + userId +
           '&organization_id=eq.' + orgId +
           '&date=gte.' + monthStart +
           '&select=date,check_in_time,check_out_time,status&order=date.desc&limit=31',
      headers: sbHeaders
    });
  }

  if (name === 'team_attendance') {
    return helpers.httpRequest({
      method: 'GET',
      url: sbUrl + '/rest/v1/attendance?organization_id=eq.' + orgId +
           '&date=eq.' + today +
           '&select=status,user:users(full_name,role)',
      headers: sbHeaders
    });
  }

  if (name === 'help') {
    const adminExtras = isAdmin ? ['\n- *Team attendance* - today\'s full team attendance', '\n- *All tasks* - view all team tasks'] : [];
    return {
      commands: [
        'list my tasks', 'create a task', 'update task status',
        'check in', 'check out', 'my attendance',
        'leave balance', 'apply leave', 'list leaves',
        'daily briefing',
        ...adminExtras
      ]
    };
  }

  return { error: 'Unknown tool: ' + name };
}

