const history = JSON.parse(ctx.history || '[]');
const roleNote = isAdmin
  ? '\n\n*Admin/Manager access:* You can list ALL team tasks, assign tasks to any member, and view team attendance.'
  : '';

const messages = [
  { role: 'system', content: ctx.system_prompt + roleNote },
  ...history,
  { role: 'user', content: ctx.message }
];

// ── LLM loop ────────────────────────────────────────────────────────────────
async function groqCall(msgs) {
  return helpers.httpRequest({
    method: 'POST',
    url: 'https://api.groq.com/openai/v1/chat/completions',
    headers: { Authorization: 'Bearer ' + groqKey, 'Content-Type': 'application/json' },
    body: JSON.stringify({
      model: 'llama-3.3-70b-versatile',
      messages: msgs,
      tools,
      tool_choice: 'auto',
      max_tokens: 1024,
      temperature: 0.3
    })
  });
}

let resp   = await groqCall(messages);
let choice = resp.choices[0];
let iters  = 0;

while (choice.finish_reason === 'tool_calls' && iters < 5) {
  const toolCalls = choice.message.tool_calls || [];
  messages.push(choice.message);

  for (const tc of toolCalls) {
    let toolResult;
    try {
      toolResult = await runTool(tc.function.name, JSON.parse(tc.function.arguments || '{}'));
    } catch(e) {
      toolResult = { error: e.message };
    }
    messages.push({
      role: 'tool',
      tool_call_id: tc.id,
      content: JSON.stringify(toolResult)
    });
  }

  resp   = await groqCall(messages);
  choice = resp.choices[0];
  iters++;
}

return [{ json: { output: choice.message.content || '' } }];

const isGreeting = $('Build Context').item.json.is_greeting;
const aiOutput = $('AI Agent').item.json.output;

if (!isGreeting) {
  return [{ json: { output: aiOutput } }];
}

